import{_ as a,c as i,o,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Registro de Cambios: Historial de Versiones y Cambios de Funcionalidad | Agent App Factory","description":"Conoce el historial de actualizaciones de versiones de Agent App Factory, cambios de funcionalidad, correcciones de bugs y mejoras importantes. Esta página detalla el historial completo de cambios desde la versión 1.0.0, incluyendo sistema de canalización de 7 etapas, planificador Sisyphus, gestión de permisos, optimización de contexto y estrategias de manejo de fallos.","frontmatter":{"title":"Registro de Cambios: Historial de Versiones y Cambios de Funcionalidad | Agent App Factory","sidebarTitle":"Registro de Cambios","subtitle":"Registro de Cambios: Historial de Versiones y Cambios de Funcionalidad | Agent App Factory","description":"Conoce el historial de actualizaciones de versiones de Agent App Factory, cambios de funcionalidad, correcciones de bugs y mejoras importantes. Esta página detalla el historial completo de cambios desde la versión 1.0.0, incluyendo sistema de canalización de 7 etapas, planificador Sisyphus, gestión de permisos, optimización de contexto y estrategias de manejo de fallos.","tags":["Registro de Cambios","Historial de Versiones"],"prerequisite":[],"order":250},"headers":[],"relativePath":"es/hyz1992/agent-app-factory/changelog/release-notes/index.md","filePath":"es/hyz1992/agent-app-factory/changelog/release-notes/index.md"}'),r={name:"es/hyz1992/agent-app-factory/changelog/release-notes/index.md"};function n(s,e,d,l,c,p){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="registro-de-cambios" tabindex="-1">Registro de Cambios <a class="header-anchor" href="#registro-de-cambios" aria-label="Permalink to &quot;Registro de Cambios&quot;">​</a></h1><p>Esta página registra el historial de actualizaciones de versiones de Agent App Factory, incluyendo nuevas funcionalidades, mejoras, correcciones de bugs y cambios disruptivos.</p><p>El formato sigue las especificaciones <a href="https://keepachangelog.com/zh-CN/1.0.0/" target="_blank" rel="noreferrer">Keep a Changelog</a> y los números de versión siguen <a href="https://semver.org/lang/zh-CN/" target="_blank" rel="noreferrer">Semantic Versioning</a>.</p><h2 id="_1-0-0-2024-01-29" tabindex="-1">[1.0.0] - 2024-01-29 <a class="header-anchor" href="#_1-0-0-2024-01-29" aria-label="Permalink to &quot;[1.0.0] - 2024-01-29&quot;">​</a></h2><h3 id="anadido" tabindex="-1">Añadido <a class="header-anchor" href="#anadido" aria-label="Permalink to &quot;Añadido&quot;">​</a></h3><p><strong>Funcionalidades Principales</strong></p><ul><li><p><strong>Sistema de canalización de 7 etapas</strong>: flujo automatizado completo desde la idea hasta la aplicación ejecutable</p><ul><li>Bootstrap - estructurar ideas de producto (input/idea.md)</li><li>PRD - generar documento de requisitos de producto (artifacts/prd/prd.md)</li><li>UI - diseñar estructura de UI y prototipos previsualizables (artifacts/ui/)</li><li>Tech - diseñar arquitectura técnica y modelo de datos Prisma (artifacts/tech/)</li><li>Code - generar código de frontend y backend (artifacts/backend/, artifacts/client/)</li><li>Validation - validar calidad del código (artifacts/validation/report.md)</li><li>Preview - generar guía de despliegue (artifacts/preview/README.md)</li></ul></li><li><p><strong>Planificador Sisyphus</strong>: componente de control central de la canalización</p><ul><li>Ejecutar cada Stage definido en pipeline.yaml en secuencia</li><li>Verificar entrada/salida y condiciones de salida de cada etapa</li><li>Mantener estado de la canalización (.factory/state.json)</li><li>Ejecutar verificaciones de permisos para evitar lecturas/escrituras no autorizadas de Agentes</li><li>Manejar situaciones anómalas según la estrategia de fallos</li><li>Pausar en cada punto de control, esperar confirmación manual antes de continuar</li></ul></li></ul><p><strong>Herramientas CLI</strong></p><ul><li><code>factory init</code> - inicializar proyecto Factory</li><li><code>factory run [stage]</code> - ejecutar canalización (desde etapa actual o especificada)</li><li><code>factory continue</code> - continuar ejecución en nueva sesión (ahorrar tokens)</li><li><code>factory status</code> - ver estado actual del proyecto</li><li><code>factory list</code> - listar todos los proyectos Factory</li><li><code>factory reset</code> - restablecer estado del proyecto actual</li></ul><p><strong>Permisos y Seguridad</strong></p><ul><li><strong>Matriz de límites de capacidades</strong> (capability.matrix.md): definir permisos de lectura/escritura estrictos para cada Agente <ul><li>Cada Agente solo puede acceder a directorios autorizados</li><li>Archivos escritos sin permiso se mueven a artifacts/_untrusted/</li><li>Suspender automáticamente la canalización tras fallo, esperar intervención manual</li></ul></li></ul><p><strong>Optimización de Contexto</strong></p><ul><li><strong>Ejecución por sesiones</strong>: cada etapa se ejecuta en una nueva sesión <ul><li>Evitar acumulación de contexto, ahorrar tokens</li><li>Soportar recuperación tras interrupciones</li><li>Compatible con todos los asistentes AI (Claude Code, OpenCode, Cursor)</li></ul></li></ul><p><strong>Estrategias de Manejo de Fallos</strong></p><ul><li>Mecanismo de reintento automático: cada etapa permite un reintento</li><li>Archivo de fallos: artefactos fallidos se mueven a artifacts/_failed/</li><li>Mecanismo de reversión: revertir al punto de control exitoso más reciente</li><li>Intervención manual: pausar tras dos fallos consecutivos</li></ul><p><strong>Aseguramiento de Calidad</strong></p><ul><li><p><strong>Estándares de código</strong> (code-standards.md)</p><ul><li>Estándares de codificación TypeScript y mejores prácticas</li><li>Estructura de archivos y convenciones de nombres</li><li>Requisitos de comentarios y documentación</li><li>Estándar de mensajes de commit de Git (Conventional Commits)</li></ul></li><li><p><strong>Estándares de códigos de error</strong> (error-codes.md)</p><ul><li>Estructura unificada de códigos de error: [MODULE]<em>[ERROR_TYPE]</em>[SPECIFIC]</li><li>Tipos estándar de error: VALIDATION, NOT_FOUND, FORBIDDEN, CONFLICT, INTERNAL_ERROR</li><li>Mapeo de códigos de error frontend/backend y mensajes amigables para usuarios</li></ul></li></ul><p><strong>Gestión de Changelog</strong></p><ul><li>Seguir formato Keep a Changelog</li><li>Integración con Conventional Commits</li><li>Soporte de herramientas automatizadas: conventional-changelog-cli, release-it</li></ul><p><strong>Plantillas de Configuración</strong></p><ul><li>Configuración CI/CD (GitHub Actions)</li><li>Configuración de Git Hooks (Husky)</li></ul><p><strong>Características de Aplicaciones Generadas</strong></p><ul><li>Código completo de frontend y backend (Express + Prisma + React Native)</li><li>Pruebas unitarias e integración (Vitest + Jest)</li><li>Documentación de API (Swagger/OpenAPI)</li><li>Datos de semilla de base de datos</li><li>Configuración de despliegue Docker</li><li>Manejo de errores y monitoreo de logs</li><li>Optimización de rendimiento y verificaciones de seguridad</li></ul><h3 id="mejorado" tabindex="-1">Mejorado <a class="header-anchor" href="#mejorado" aria-label="Permalink to &quot;Mejorado&quot;">​</a></h3><p><strong>Enfoque MVP</strong></p><ul><li>Listar explícitamente objetivos no incluidos (Non-Goals), prevenir expansión de alcance</li><li>Limitar número de páginas a 3 como máximo</li><li>Enfocarse en funcionalidades principales, evitar sobrediseño</li></ul><p><strong>Separación de Responsabilidades</strong></p><ul><li>Cada Agente solo responsable de su dominio, no cruzar límites</li><li>PRD no contiene detalles técnicos, Tech no involucra diseño UI</li><li>Code Agent implementa estrictamente según esquema UI y diseño Tech</li></ul><p><strong>Verificabilidad</strong></p><ul><li>Cada etapa define exit_criteria claros</li><li>Todas las funcionalidades son probables y ejecutables localmente</li><li>Artefactos deben estar estructurados y ser consumibles por etapas posteriores</li></ul><h3 id="stack-tecnologico" tabindex="-1">Stack Tecnológico <a class="header-anchor" href="#stack-tecnologico" aria-label="Permalink to &quot;Stack Tecnológico&quot;">​</a></h3><p><strong>Herramientas CLI</strong></p><ul><li>Node.js &gt;= 16.0.0</li><li>Commander.js - framework de línea de comandos</li><li>Chalk - salida de terminal coloreada</li><li>Ora - indicador de progreso</li><li>Inquirer - línea de comandos interactiva</li><li>fs-extra - operaciones de sistema de archivos</li><li>YAML - análisis YAML</li></ul><p><strong>Aplicaciones Generadas</strong></p><ul><li>Backend: Node.js + Express + Prisma + TypeScript + Vitest</li><li>Frontend: React Native + Expo + TypeScript + Jest + React Testing Library</li><li>Despliegue: Docker + GitHub Actions</li></ul><h3 id="dependencias" tabindex="-1">Dependencias <a class="header-anchor" href="#dependencias" aria-label="Permalink to &quot;Dependencias&quot;">​</a></h3><ul><li><code>chalk@^4.1.2</code> - estilos de color de terminal</li><li><code>commander@^11.0.0</code> - análisis de argumentos de línea de comandos</li><li><code>fs-extra@^11.1.1</code> - extensiones de sistema de archivos</li><li><code>inquirer@^8.2.5</code> - línea de comandos interactiva</li><li><code>ora@^5.4.1</code> - cargador de terminal elegante</li><li><code>yaml@^2.3.4</code> - análisis y serialización YAML</li></ul><h2 id="notas-de-version" tabindex="-1">Notas de Versión <a class="header-anchor" href="#notas-de-version" aria-label="Permalink to &quot;Notas de Versión&quot;">​</a></h2><h3 id="semantic-versioning" tabindex="-1">Semantic Versioning <a class="header-anchor" href="#semantic-versioning" aria-label="Permalink to &quot;Semantic Versioning&quot;">​</a></h3><p>Este proyecto sigue el formato de número de versión <a href="https://semver.org/lang/zh-CN/" target="_blank" rel="noreferrer">Semantic Versioning</a>: MAJOR.MINOR.PATCH</p><ul><li><strong>MAJOR</strong>: cambios de API incompatibles</li><li><strong>MINOR</strong>: nuevas funcionalidades con compatibilidad hacia atrás</li><li><strong>PATCH</strong>: correcciones de bugs compatibles hacia atrás</li></ul><h3 id="tipos-de-cambios" tabindex="-1">Tipos de Cambios <a class="header-anchor" href="#tipos-de-cambios" aria-label="Permalink to &quot;Tipos de Cambios&quot;">​</a></h3><ul><li><strong>Añadido</strong> (Added): nuevas funcionalidades</li><li><strong>Cambiado</strong> (Changed): cambios en funcionalidades existentes</li><li><strong>Obsoleto</strong> (Deprecated): funcionalidades que se eliminarán pronto</li><li><strong>Eliminado</strong> (Removed): funcionalidades eliminadas</li><li><strong>Corregido</strong> (Fixed): correcciones de bugs</li><li><strong>Seguridad</strong> (Security): correcciones de seguridad</li></ul><h2 id="recursos-relacionados" tabindex="-1">Recursos Relacionados <a class="header-anchor" href="#recursos-relacionados" aria-label="Permalink to &quot;Recursos Relacionados&quot;">​</a></h2><ul><li><a href="https://github.com/hyz1992/agent-app-factory/releases" target="_blank" rel="noreferrer">GitHub Releases</a> - página oficial de lanzamientos</li><li><a href="https://github.com/hyz1992/agent-app-factory" target="_blank" rel="noreferrer">Repositorio del proyecto</a> - código fuente</li><li><a href="https://github.com/hyz1992/agent-app-factory/issues" target="_blank" rel="noreferrer">Seguimiento de problemas</a> - reportar problemas y sugerencias</li><li><a href="https://github.com/hyz1992/agent-app-factory/blob/main/CONTRIBUTING.md" target="_blank" rel="noreferrer">Guía de contribución</a> - cómo contribuir</li></ul><hr><h2 id="apendice-referencia-de-codigo-fuente" tabindex="-1">Apéndice: Referencia de Código Fuente <a class="header-anchor" href="#apendice-referencia-de-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia de Código Fuente&quot;">​</a></h2><details><summary><strong>Haz clic para expandir y ver ubicación del código fuente</strong></summary><blockquote><p>Actualizado: 2024-01-29</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidad</th><th>Ruta del archivo</th><th>Línea</th></tr></thead><tbody><tr><td>package.json</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/package.json" target="_blank" rel="noreferrer"><code>package.json</code></a></td><td>1-52</td></tr><tr><td>Entrada CLI</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/bin/factory.js" target="_blank" rel="noreferrer"><code>cli/bin/factory.js</code></a></td><td>1-123</td></tr><tr><td>Comando de inicialización</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/commands/init.js" target="_blank" rel="noreferrer"><code>cli/commands/init.js</code></a></td><td>1-427</td></tr><tr><td>Comando de ejecución</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/commands/run.js" target="_blank" rel="noreferrer"><code>cli/commands/run.js</code></a></td><td>1-294</td></tr><tr><td>Comando de continuación</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/commands/continue.js" target="_blank" rel="noreferrer"><code>cli/commands/continue.js</code></a></td><td>1-87</td></tr><tr><td>Definición de canalización</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/pipeline.yaml" target="_blank" rel="noreferrer"><code>pipeline.yaml</code></a></td><td>1-87</td></tr><tr><td>Definición de planificador</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/orchestrator.checkpoint.md" target="_blank" rel="noreferrer"><code>agents/orchestrator.checkpoint.md</code></a></td><td>1-301</td></tr><tr><td>Matriz de permisos</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/capability.matrix.md" target="_blank" rel="noreferrer"><code>policies/capability.matrix.md</code></a></td><td>1-44</td></tr><tr><td>Política de fallos</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/failure.policy.md" target="_blank" rel="noreferrer"><code>policies/failure.policy.md</code></a></td><td>1-200</td></tr><tr><td>Estándares de código</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/code-standards.md" target="_blank" rel="noreferrer"><code>policies/code-standards.md</code></a></td><td>1-287</td></tr><tr><td>Estándares de códigos de error</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/error-codes.md" target="_blank" rel="noreferrer"><code>policies/error-codes.md</code></a></td><td>1-134</td></tr><tr><td>Especificación de Changelog</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/changelog.md" target="_blank" rel="noreferrer"><code>policies/changelog.md</code></a></td><td>1-87</td></tr></tbody></table><p><strong>Información clave de versiones</strong>:</p><ul><li><code>version = &quot;1.0.0&quot;</code>: versión de lanzamiento inicial</li><li><code>engines.node = &quot;&gt;=16.0.0&quot;</code>: requisito mínimo de versión Node.js</li></ul><p><strong>Versiones de dependencias</strong>:</p><ul><li><code>chalk@^4.1.2</code>: estilos de color de terminal</li><li><code>commander@^11.0.0</code>: análisis de argumentos de línea de comandos</li><li><code>fs-extra@^11.1.1</code>: extensiones de sistema de archivos</li><li><code>inquirer@^8.2.5</code>: línea de comandos interactiva</li><li><code>ora@^5.4.1</code>: cargador de terminal elegante</li><li><code>yaml@^2.3.4</code>: análisis y serialización YAML</li></ul></details>',48)])])}const g=a(r,[["render",n]]);export{m as __pageData,g as default};
